import 'package:flutter/material.dart';
import 'package:local_auth/local_auth.dart';
import 'package:shared_preferences/shared_preferences.dart';

class BiometricAuthScreen extends StatefulWidget {
  @override
  _BiometricAuthScreenState createState() => _BiometricAuthScreenState();
}

class _BiometricAuthScreenState extends State<BiometricAuthScreen> {
  bool _isAuthenticated = false;
  bool _isBiometricsAvailable = true;

  @override
  void initState() {
    super.initState();
    checkBiometricsAvailability();
  }

  Future<void> checkBiometricsAvailability() async {
    final LocalAuthentication auth = LocalAuthentication();
    bool canCheckBiometrics;
    try {
      canCheckBiometrics = await auth.isDeviceSupported;
    } on PlatformException catch (e) {
      print(e);
    }
    if (!mounted) return;

    setState(() {
      _isBiometricsAvailable = canCheckBiometrics;
    });
  }

  Future<void> authenticate() async {
    final LocalAuthentication auth = LocalAuthentication();
    bool isAuthenticated;
    try {
      isAuthenticated = await auth.authenticateWithBiometrics(
        localizedReason: 'Please authenticate to access the app',
        useErrorDialogs: true,
        stickyAuth: false,
      );
    } on PlatformException catch (e) {
      print(e);
    }
    if (!mounted) return;

    setState(() {
      _isAuthenticated = isAuthenticated;
    });
  }

  Future<void> saveAuthenticationStatus() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    prefs.setBool('is_authenticated', _isAuthenticated);
